	const result = await fetch('http://localhost:5001/login', {
		method:'POST',
		body:JSON.stringify(userData),
		headers:{'Content-type':'application/json'}
	})
	const data = await result.json()
	dispatch(storeUser({
		id:data.id,
		username:data.username
	}))
	localStorage.setItem('isAuth', data.isAuth)
	localStorage.setItem('token', data.token)
}

const getMe = async(token, dispatch, loginAction, logoutAction) => {
	const result = await fetch('http://localhost:5001/getMe', {
		method:'GET',
		headers:{authorization: `Bearer ${token}`}
	})
	if (result.status !== 401 && result.status !== 403) {
		//const data = await result.json()
		dispatch(loginAction())
	} else {
		const refreshToken = {
			refreshToken:localStorage.getItem('token')
		}
		const result = await fetch('http://localhost:5001/token', {
			method:'POST',
			body:JSON.stringify(refreshToken),
			headers:{'Content-type':'application/json'}
		})
		if (result.status === 401 || result.status === 403) {
			dispatch(logoutAction())
			localStorage.removeItem('isAuth')
			localStorage.removeItem('token')
		} else {
			const data = await result.json()

			const reLoginResult = await fetch('http://localhost:5001/getMe', {
				method:'GET',
				headers:{authorization: `Bearer ${data.accessToken}`}
			})
			dispatch(loginAction())
			localStorage.setItem('isAuth', data.accessToken)
		}
	}
}

